            if isinstance(response, tuple):
                response_data, status_code = response[0], response[1]
            else:
                response_data = response
                status_code = 200
            
            logger.info(f"RESPONSE [{request_id}]: Status={status_code}, Data={json.dumps(response_data.get_json() if hasattr(response_data, 'get_json') else str(response_data), indent=2)}")
            
